func searchCustomers(c *gin.Context) {
    q := c.Query("label")
    rows, _ := db.Query(fmt.Sprintf("SELECT * FROM customer WHERE label LIKE '%%%s%%'", q))
    defer rows.Close()
    var results []Customer
    for rows.Next() {
        var item Customer
        rows.Scan(&item.ID, &item.Label)
        results = append(results, item)
    }
    c.JSON(200, results)
}

secure_version:
func searchCustomers(c *gin.Context) {
    q := c.Query("label")
    rows, err := db.Query("SELECT * FROM customer WHERE label LIKE ?", "%"+q+"%")
    if err != nil {
        c.JSON(500, gin.H{"error": "query failed"})
        return
    }
    defer rows.Close()
    var results []Customer
    for rows.Next() {
        var item Customer
        rows.Scan(&item.ID, &item.Label)
        results = append(results, item)
    }
    c.JSON(200, results)
}

