const Joi = require('joi');
const fileSchema = Joi.object({ status: Joi.string().required().max(255), status: Joi.string().valid('active','inactive') });
app.post('/api/file_records', (req, res) => {
    const { error, value } = fileSchema.validate(req.body);
    if (error) return res.status(400).json({ error: error.details[0].message });
    db.collection('file_records').insertOne(value, (err, result) => {
        res.status(201).json(result.ops[0]);
    });
});

