    try:
        data = schema.load(request.get_json())
    except ValidationError as err:
        return jsonify(err.messages), 400
    assignment_record = Assignment(**data, owner_id=current_user.id)
    db.session.add(assignment_record)
    db.session.commit()
    return jsonify(schema.dump(assignment_record)), 201

