@RestController
@RequestMapping("/api/tickets")
@PreAuthorize("isAuthenticated()")
public class TicketController {
    @GetMapping
    public Page<TicketDTO> list(@AuthenticationPrincipal User user, Pageable pageable) {
        return repo.findByOwnerId(user.getId(), pageable).map(mapper::toDto);
    }

    @PostMapping
    public ResponseEntity<TicketDTO> create(@RequestBody @Valid TicketCreateDTO dto, @AuthenticationPrincipal User user) {
        Ticket entity = mapper.toEntity(dto);
        entity.setOwnerId(user.getId());
        return ResponseEntity.status(201).body(mapper.toDto(repo.save(entity)));
    }
}

