app.get('/api/invoice_entries', authenticate, async (req, res) => {
    const page = parseInt(req.query.page) || 1;
    const limit = Math.min(parseInt(req.query.limit) || 20, 100);
    const items = await Invoice.find({ owner: req.user.id })
        .skip((page - 1) * limit)
        .limit(limit)
        .lean();
    const total = await Invoice.countDocuments({ owner: req.user.id });
    res.json({ items, total, page });
});

